			cxPropAllowMultiple : Lyte.attr('boolean', { "default" : false}), //NO I18n
	    cxPropCustomRequest : Lyte.attr('boolean', { "default" : false}), //NO I18n
			
			cxPropViewWidth : Lyte.attr("string", { "default" : "40%"}), //NO I18n
