			cxPropNoUserAvilableMsg : Lyte.attr("string", { "default" :_cruxUtils.getI18n('crm.security.group.users.empty') }), //NO I18n
			cxPropTransition : Lyte.attr('object' , {"default" : {"animation":"slideFromTop","duration":"0.4"}}), //NO I18n
